import React from "react";
import MasonryGrid from "./MasonryGrid";
import Wave from "../DecorationComponents/wavecircle.svg";



const Galeria = () => {
  return (
    <section className="h-screen snap-start overflow-hidden relative bg-white flex flex-col justify-center">

      <div className="pointer-events-none absolute inset-0 z-0 overflow-hidden">
  <img
    src={Wave}
    className="absolute w-[150vw] animate-spin-slow"
    style={{ top: '-65%', right: '-55vw', transformOrigin: 'center center' }}
  />
</div>

<div className="pointer-events-none absolute inset-0 z-0 overflow-hidden">
  <img
    src={Wave}
    className="absolute w-[150vw] animate-spin-slow-reverse"
    style={{ top: '-30%', left: '-50vw', transformOrigin: 'center center' }}
  />
</div>

      {/* CONTENIDO */}
      <div className="relative z-10 text-center mb-[3vh]">
        <h1 className="titulo-playfair font-semibold text-[#7D6239] text-[2rem]">
          ¿Te quedaste con ganas de ver más?
        </h1>
        <div className="h-[5px] w-[3rem] mx-auto rounded-full bg-gradient-to-r from-[#CC2329] to-[#F55809]" />
      </div>

      <div className=" relative z-10 w-[50%] mx-auto ">
        <MasonryGrid />
      </div>

    </section>
  );
};

export default Galeria;
